import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const b=JSON.parse('{"title":"Дом Александра Башлачёва","description":"Дом на Сакко и Ванцетти, связанный со студенческими годами Александра Башлачёва, квартирниками и памятью о свердловском андеграунде.","frontmatter":{"title":"Дом Александра Башлачёва","description":"Дом на Сакко и Ванцетти, связанный со студенческими годами Александра Башлачёва, квартирниками и памятью о свердловском андеграунде.","outline":"deep"},"headers":[],"relativePath":"places/bashlachev-house.md","filePath":"places/bashlachev-house.md"}'),d={name:"places/bashlachev-house.md"};function s(h,a,o,i,n,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="дом-александра-башлачева" tabindex="-1">Дом Александра Башлачёва <a class="header-anchor" href="#дом-александра-башлачева" aria-label="Permalink to “Дом Александра Башлачёва”">​</a></h1><p><strong>Дом Александра Башлачёва</strong> на улице Сакко и Ванцетти — одно из самых известных личных рок-мест Екатеринбурга. Это здание связано со студенческими годами поэта и музыканта, его квартирниками, ранними текстами и образом «заколдованного дома», который вошёл в мифологию русского рока.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Сакко и Ванцетти, 24</li><li><strong>Период ключевого значения:</strong> конец 1970-х — начало 1980-х годов</li><li><strong>Главная роль:</strong> место студенческой жизни Александра Башлачёва в Свердловске</li><li><strong>Связанные темы:</strong> квартирники, студенческий андеграунд, поэзия, ранняя рок-среда</li><li><strong>Статус сегодня:</strong> объект культурного наследия регионального значения</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Дом на Сакко и Ванцетти важен как личное и поэтическое место уральского рока. В отличие от ДК, фестивальных площадок и репетиционных подвалов, здесь история связана с камерной средой: студенческой жизнью, квартирниками, разговорами, стихами и ранним творчеством Александра Башлачёва.</p><p>Для поклонников Башлачёва это место стало символическим адресом. С ним связывают его свердловский период, первые музыкальные и поэтические опыты, а также атмосферу студенческого андеграунда конца 1970-х — начала 1980-х годов.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Дом по улице Сакко и Ванцетти — одно из заметных исторических зданий Екатеринбурга. Изначально он был главным домом усадьбы купцов Агафуровых. Здание относится к концу XIX века и окончательно сформировало свой облик в 1892 году после перестройки по проекту архитектора Ю. О. Дютеля.</p><p>Архитектурно дом представляет собой яркий пример эклектики: в его облике соединяются восточные мотивы, уральские традиции резьбы по дереву и элементы классицизма. Однако для истории уральского рока это здание важно не только как памятник архитектуры, но и как место, связанное с Александром Башлачёвым.</p><p>Башлачёв приехал в Свердловск в 1978 году и поступил на журфак Уральского государственного университета. Сначала он жил в общежитии на улице Большакова, а затем оказался в доме на Сакко и Ванцетти. К тому времени здание было расселено, и власти планировали его снести. Чтобы сохранить дома-памятники, местное отделение ВООПИК предложило студентам поселиться в этих зданиях.</p><p>Так Александр Башлачёв оказался в особняке на Сакко и Ванцетти. Вместе с ним здесь жили другие студенты журфака и архитектурного института. В комнате на первом этаже Башлачёв писал стихи и музыку, встречался с друзьями и устраивал квартирники. По некоторым рассказам, именно в этот период произошло его знакомство с Вячеславом Бутусовым.</p><p>Свердловск оказал на Башлачёва заметное влияние. Он прожил здесь до 1983 года, пока учился на журфаке, а диплом посвятил музыкальной критике. Позже, уже после переезда в Ленинград, он ещё несколько раз возвращался в Свердловск как известный андеграундный музыкант.</p><p>Дом также вошёл в песенную мифологию Башлачёва. В песне <strong>«Поезд»</strong> он упоминает образ «заколдованного дома». В старых источниках и воспоминаниях встречается номер 22, но исследователи связывают этот адрес с нынешним домом № 24 из-за изменений в нумерации улицы.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Сакко и Ванцетти, 24.</p><p>Дом находится в центральной части Екатеринбурга и хорошо подходит для пеших маршрутов, посвящённых Александру Башлачёву, студенческому Свердловску и культурной памяти уральского рока.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/alexander-bashlachev.html">Александр Башлачёв</a></td><td>Поэт и музыкант, жил здесь в студенческие годы, называл дом «заколдованным»</td></tr><tr><td><a href="/Knowledge-Base/people/vyacheslav-butusov.html">Вячеслав Бутусов</a></td><td>По некоторым рассказам, познакомился с Башлачёвым в этот период</td></tr><tr><td>Студенты журфака УрГУ</td><td>Соседи Башлачёва по дому, часть студенческой среды</td></tr><tr><td>Студенты архитектурного института</td><td>Жили в доме вместе с другими студентами</td></tr><tr><td>Купцы Агафуровы</td><td>Исторические владельцы усадьбы</td></tr><tr><td>Ю. О. Дютель</td><td>Архитектор, перестраивавший здание в 1892 году</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><p>На текущем этапе в материалах проекта дом связан прежде всего с Александром Башлачёвым, квартирниками и студенческой андеграундной средой, а не с конкретной группой.</p><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание является <strong>объектом культурного наследия народов Российской Федерации регионального значения</strong>. В главном усадебном доме располагается <strong>Постоянное представительство Республики Татарстан в Свердловской области</strong>.</p><p>В 2015 году, к 55-летию Александра Башлачёва, поклонники установили на доме мемориальную доску в форме пристенного бюста с надписью: <strong>«Нет тех, кто не стоит любви»</strong>.</p><p>Для поклонников Башлачёва дом остаётся местом памяти и паломничества. Сюда приходят, чтобы увидеть адрес, связанный с его студенческими годами, вспомнить песни и почувствовать атмосферу старого Свердловска.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Здание имеет современную административную функцию, поэтому свободный доступ внутрь может быть ограничен. Для маршрута по рок-местам дом лучше рассматривать как внешнюю точку с историческим комментарием.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока дом Александра Башлачёва включается в туристические маршруты по рок-местам Екатеринбурга как одна из ключевых личных локаций, связанных с поэзией, квартирниками и студенческим андеграундом.</p><p>Возможны экскурсии, литературные вечера и камерные музыкальные события в окрестностях дома, которые будут воссоздавать атмосферу студенческого Свердловска начала 1980-х годов.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Включение дома в маршруты по рок-местам Екатеринбурга</td></tr><tr><td>2026 год</td><td>Возможные экскурсии, посвящённые Александру Башлачёву и студенческому Свердловску</td></tr><tr><td>2026 год</td><td>Возможные литературные вечера и камерные концерты-квартирники в окрестностях дома</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Дом Александра Башлачёва удобно включать в маршрут по центральным местам свердловского андеграунда. Его можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/school-2.html">Школа № 2</a></li></ul>',33)])])}const g=t(d,[["render",s]]);export{b as __pageData,g as default};
